function process_refund( $order_id, $amount = null, $reason = '' ) {
		$order = wc_get_order( $order_id );

		if ( ! $order ) {
			return new WP_Error(
				'woocommerce_stripe_invalid_order',
				__( 'Invalid order.', 'woocommerce-gateways' )
			);
		}

		$existing_refund_id = $this->get_existing_refund_id( $order );
		if ( $existing_refund_id ) {
			return new WP_Error(
				'woocommerce_stripe_duplicate_refund',
				sprintf(
					/* translators: 1: refund ID 2: order number */
					__( 'Duplicate refund request for order #%1$s (refund ID %2$s).', 'woocommerce-gateways' ),
					$order->get_order_number(),
					$existing_refund_id
				)
			);
		}

		$charge_id = $this->get_charge_id_from_order( $order );
		if ( ! $charge_id ) {
			return new WP_Error(
				'woocommerce_stripe_no_charge_id',
				sprintf(
					/* translators: 1: order number */
					__( 'No Stripe charge ID found for order #%1$s.', 'woocommerce-gateways' ),
					$order->get_order_number()
				)
			);
		}

		$refund = $this->api_request(
			'refunds',
			'POST',
			array(
				'amount' => $amount,
				'charge' => $charge_id,
				'reason' => $reason,
			)
		);

		if ( is_wp_error( $refund ) ) {
			return $refund;
		}

		$order->add_order_note(
			sprintf(
				/* translators: 1: refund amount 2: refund ID */
				__( 'Refund of %1$s via Stripe (Refund ID: %2$s)', 'woocommerce-gateways' ),
				$refund['amount'],
				$refund['id']
			)
		);

		$this->save_refund_id_to_order( $order, $refund['id'] );

		return true;
	}
